import type { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { HTMLAttributes, ReactNode } from 'react';
export interface BottomSheetProps extends HTMLAttributes<HTMLDivElement> {
    /**
     * Состояние компонента - открыт/закрыт
     */
    isOpen: boolean;
    /**
     * Функция управления isOpen. Нужна для того что бы компонент мог закрыться, например, при свайпе.
     * @param arg Новое значение isOpen
     * @returns void
     */
    handleSetOpen: (arg: boolean) => void;
    /**
     * Обработчик события - клик вне элемента. С помощью него можно реализовать закрытие по клику вне элемента.
     * @param arg Event
     * @returns void
     */
    onOutsideClick?: (arg: Event) => void;
    /**
     * id корневого тега страницы для портала
     */
    applicationRootElementID?: string;
    /**
     * id корневого тега компонента для портала
     */
    dropdownElementID?: string;
    /**
     * Указывает, нужно ли рендерить компонент в портале
     * @default false
     */
    usePortal?: boolean;
    /**
     * Обработчик клика на крестик. Если не используется будет вызван handleSetOpen
     * @param event Event
     * @returns void
     */
    onClose?: (event: Event) => void;
    /**
     * Включить/выключить темную подложку.
     */
    modal?: boolean;
    /**
     * Включить/выключить свайпер - возможность изменять высоту компонента. Доступно только на устройствах с тачскрином.
     */
    swiper?: boolean;
    /**
     * Заголовок компонентв.
     * @param title Заголовок
     * @param icon Иконка, используйте Icons из иконочного шрифта
     * @param subtitle Подзаголовок
     * @param closeButton Крестик для закрытия
     * @param divider Разделитель снизу
     * @param actionButton Кнопка вместо крестика для закрытия. Включает в себя label и опциональный onClick
     */
    header?: BottomSheetHeader;
    /**
     * Одно или два действия для bottomActionBar в компоненте.
     * @param label Текст кнопки
     * @param variant Тип - желтая или обычная кнопка
     * @param onClick
     */
    actions?: BottomSheetActionsType;
    /**
     * Содержимое компонента. ReactNode
     */
    children?: ReactNode;
    /**
     * Кастомный класс
     */
    className?: string;
    /**
     * Степени "открытия" компонента. Могут быть обозначены как абсолютная высота, относительная и высота высчитанная от максимума.
     * Максимум считается так: МаксимальнаяВысотаОкна - Отступ (на данный момент по ДС - 64px)
     * Абсолютная высота задается числом от 1 до максимальной высоты, например: 100, 234, 453 и тд
     * Относительная высота задается числом от 0 до 1, например: 0.2, 0.5, 0.7 (20%, 50%, 70% от максимума соответственно)
     * Высота от максимума задается как отрицательное число, например: -100, -200, -300 (Максимум-100, Максимум-200, Максимум-300 соответственно)
     */
    snapPoints?: number[];
    /**
     * Значение, на которое открывается компонент. Индекс (!!!) из массива snapPoints
     */
    initialSnapPoint?: number;
    /**
     * Кастомные стили
     */
    style?: React.CSSProperties;
}
export type BottomSheetActionsType = [BottomSheetActionsButton, BottomSheetActionsButton] | [BottomSheetActionsButton];
export interface BottomSheetHeader {
    title?: string;
    icon?: Icons;
    subtitle?: string;
    closeButton?: boolean;
    divider?: boolean;
    actionButton?: {
        label: string;
        onClick?: () => void;
    };
}
export interface BottomSheetActionsButton {
    label: string;
    variant?: 'contained' | 'outlined';
    onClick?: () => void;
}
